"use client";

import { useEffect, useMemo, useState } from "react";
import { useAccount, useBalance, useSendTransaction } from "wagmi";
import { parseEther } from "viem";
import { io } from "socket.io-client";

import { TOKENS } from "@/lib/tokens";

import ReceiveModal from "./components/ReceiveModal";
import VirtualCard from "./components/VirtualCard";
import TransactionHistory from "./components/TransactionHistory";
import BottomNav from "./components/BottomNav";
import Scanner from "./components/Scanner";

/* SOCKET */
const socket = io("https://iopndex.onrender.com", {
  transports: ["websocket"],
  });

  function formatBalance(value: any) {
    if (!value) return "0.00";
      return Number(value.formatted || 0).toFixed(2);
      }

      export default function PayPage() {
        const { address, isConnected } = useAccount();

          const [recipient, setRecipient] = useState("");
            const [amount, setAmount] = useState("");
              const [tokenSymbol, setTokenSymbol] = useState("OPN");

                const [txHash, setTxHash] = useState<string | null>(null);
                  const [liveTxs, setLiveTxs] = useState<any[]>([]);

                    /* MODALS */
                      const [showReceive, setShowReceive] = useState(false);
                        const [showCard, setShowCard] = useState(false);
                          const [showScanner, setShowScanner] = useState(false);

                            const { data: balance } = useBalance({ address });

                              const { sendTransactionAsync } = useSendTransaction();

                                const token = useMemo(
                                    () => TOKENS.find((t) => t.symbol === tokenSymbol),
                                        [tokenSymbol]
                                          );

                                            /* SEND TX */
                                              async function sendTx() {
                                                  if (!isConnected || !address) {
                                                        alert("Connect wallet");
                                                              return;
                                                                  }

                                                                      if (!recipient || !amount) {
                                                                            alert("Missing fields");
                                                                                  return;
                                                                                      }

                                                                                          try {
                                                                                                const tx = await sendTransactionAsync({
                                                                                                        to: recipient as `0x${string}`,
                                                                                                                value: parseEther(amount),
                                                                                                                      });

                                                                                                                            setTxHash(tx);

                                                                                                                                  await fetch("https://iopndex.onrender.com/api/send", {
                                                                                                                                          method: "POST",
                                                                                                                                                  headers: { "Content-Type": "application/json" },
                                                                                                                                                          body: JSON.stringify({
                                                                                                                                                                    from: address,
                                                                                                                                                                              to: recipient,
                                                                                                                                                                                        amount,
                                                                                                                                                                                                  token: tokenSymbol,
                                                                                                                                                                                                            hash: tx,
                                                                                                                                                                                                                      chainId: 984,
                                                                                                                                                                                                                              }),
                                                                                                                                                                                                                                    });

                                                                                                                                                                                                                                          setRecipient("");
                                                                                                                                                                                                                                                setAmount("");

                                                                                                                                                                                                                                                      alert("Transaction sent 🚀");
                                                                                                                                                                                                                                                          } catch (err) {
                                                                                                                                                                                                                                                                console.error(err);
                                                                                                                                                                                                                                                                      alert("Failed ❌");
                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                              /* SOCKET */
                                                                                                                                                                                                                                                                                useEffect(() => {
                                                                                                                                                                                                                                                                                    socket.on("newTx", (tx) => {
                                                                                                                                                                                                                                                                                          setLiveTxs((prev) => [tx, ...prev]);
                                                                                                                                                                                                                                                                                              });

                                                                                                                                                                                                                                                                                                  socket.on("txConfirmed", (data) => {
                                                                                                                                                                                                                                                                                                        setLiveTxs((prev) =>
                                                                                                                                                                                                                                                                                                                prev.map((tx) =>
                                                                                                                                                                                                                                                                                                                          tx.hash === data.hash
                                                                                                                                                                                                                                                                                                                                      ? { ...tx, status: "confirmed" }
                                                                                                                                                                                                                                                                                                                                                  : tx
                                                                                                                                                                                                                                                                                                                                                          )
                                                                                                                                                                                                                                                                                                                                                                );
                                                                                                                                                                                                                                                                                                                                                                    });

                                                                                                                                                                                                                                                                                                                                                                        return () => {
                                                                                                                                                                                                                                                                                                                                                                              socket.off("newTx");
                                                                                                                                                                                                                                                                                                                                                                                    socket.off("txConfirmed");
                                                                                                                                                                                                                                                                                                                                                                                        };
                                                                                                                                                                                                                                                                                                                                                                                          }, []);

                                                                                                                                                                                                                                                                                                                                                                                            return (
                                                                                                                                                                                                                                                                                                                                                                                                <div className="min-h-screen bg-black text-white p-4 pb-28">

                                                                                                                                                                                                                                                                                                                                                                                                      {/* HEADER */}
                                                                                                                                                                                                                                                                                                                                                                                                            <div className="mb-4">
                                                                                                                                                                                                                                                                                                                                                                                                                    <h1 className="text-2xl font-bold">IOPN Pay</h1>

                                                                                                                                                                                                                                                                                                                                                                                                                            <p className="text-white/60">
                                                                                                                                                                                                                                                                                                                                                                                                                                      Balance: {formatBalance(balance)} {tokenSymbol}
                                                                                                                                                                                                                                                                                                                                                                                                                                              </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                          {/* TOKEN */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                <select
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        className="w-full p-3 bg-white/10 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                value={tokenSymbol}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        onChange={(e) => setTokenSymbol(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {TOKENS.map((t) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <option key={t.symbol} value={t.symbol}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {t.symbol}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </select>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {/* SEND FORM */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="space-y-3 mt-4">

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  className="w-full p-3 bg-white/10 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            placeholder="Recipient"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      value={recipient}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                onChange={(e) => setRecipient(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          className="w-full p-3 bg-white/10 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    placeholder="Amount"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              value={amount}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        onChange={(e) => setAmount(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  onClick={sendTx}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            className="w-full bg-green-500 text-black font-bold p-3 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              Send
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </button>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {/* ACTION BUTTONS */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="flex gap-2 mt-4">

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          onClick={() => setShowReceive(true)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    className="flex-1 bg-white/10 p-3 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      Receive
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </button>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                onClick={() => setShowCard(true)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          className="flex-1 bg-white/10 p-3 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            Card
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </button>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      onClick={() => setShowScanner(true)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                className="flex-1 bg-white/10 p-3 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  Scan
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </button>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {/* HISTORY */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <TransactionHistory
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    address={address}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            liveTxs={liveTxs}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {/* MODALS */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <ReceiveModal
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      isOpen={showReceive}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              onClose={() => setShowReceive(false)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      address={address}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <VirtualCard
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          isOpen={showCard}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  onClose={() => setShowCard(false)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          balance={formatBalance(balance)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  token={tokenSymbol}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          address={address}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <Scanner
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              isOpen={showScanner}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      onClose={() => setShowScanner(false)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              onScan={(addr) => setRecipient(addr)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {/* NAV */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <BottomNav
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        active="pay"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                onChange={(tab) => alert(tab)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {txHash && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <p className="text-xs text-green-400 mt-4 break-all">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {txHash}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }